// Detect if binary data (PDF/Excel file) is present
// Also preserve parsed workbook payloads sent by the backend for n8n Cloud-safe VN processing.

let hasBinaryData = false;
let binaryKeys = [];
let binaryData = null;

const inputJson = $input.first().json || {};
const body = (inputJson.body && typeof inputJson.body === 'object') ? inputJson.body : inputJson;
const parsedWorkbook = body.parsedWorkbook || inputJson.parsedWorkbook || null;
const incomingFileName = body.filename || body.fileName || inputJson.filename || inputJson.fileName || '';
const incomingMimeType = body.mimetype || body.mimeType || inputJson.mimetype || inputJson.mimeType || '';

// Method 1: Check $binary directly
try {
  const binaryDataInput = $binary;
  if (binaryDataInput && typeof binaryDataInput === 'object') {
    binaryKeys = Object.keys(binaryDataInput);
    if (binaryKeys.length > 0) {
      hasBinaryData = true;
      binaryData = binaryDataInput;
    }
  }
} catch (e) {
  // $binary not available
}

// Method 2: Check $input.first().binary
if (!hasBinaryData) {
  try {
    const inputBinary = $input.first().binary;
    if (inputBinary && typeof inputBinary === 'object') {
      binaryKeys = Object.keys(inputBinary);
      if (binaryKeys.length > 0) {
        hasBinaryData = true;
        binaryData = inputBinary;
      }
    }
  } catch (e) {
    // Not available
  }
}

// Method 3: Check items array
if (!hasBinaryData) {
  try {
    const items = $input.all();
    for (const item of items) {
      if (item.binary && Object.keys(item.binary).length > 0) {
        hasBinaryData = true;
        binaryKeys = Object.keys(item.binary);
        binaryData = item.binary;
        break;
      }
    }
  } catch (e) {
    // Not available
  }
}

// Method 4: Convert base64 JSON payload to binary
if (!hasBinaryData) {
  try {
    let base64 = body.file || body.data || body.pdf || null;
    if (typeof base64 === 'string' && base64.trim().length > 0) {
      base64 = base64.trim();

      if (/^data:.*;base64,/i.test(base64)) {
        base64 = base64.replace(/^data:.*;base64,/i, '');
      }

      hasBinaryData = true;
      binaryKeys = ['data'];
      binaryData = {
        data: {
          data: base64,
          mimeType: incomingMimeType || 'application/octet-stream',
          fileName: incomingFileName || 'upload.bin'
        }
      };
    }
  } catch (e) {
    // Ignore conversion errors
  }
}

console.log('Binary detection result:', hasBinaryData, 'Keys:', binaryKeys, 'Has parsedWorkbook:', !!parsedWorkbook);

const outputItem = {
  ...inputJson,
  _hasBinaryData: hasBinaryData,
  _binaryKeys: binaryKeys
};

if (parsedWorkbook) {
  outputItem.parsedWorkbook = parsedWorkbook;
}

if (incomingFileName && !outputItem.filename) {
  outputItem.filename = incomingFileName;
}

if (incomingMimeType && !outputItem.mimetype) {
  outputItem.mimetype = incomingMimeType;
}

if (hasBinaryData) {
  return [{
    json: outputItem,
    binary: binaryData || $input.first().binary
  }];
}

return [{
  json: outputItem
}];

// Prepare input text from PDF extraction
// Get extracted text from PDF - check multiple possible locations
const pdfData = $input.first().json;
let inputText = '';

// Try different possible locations for the extracted text
if (pdfData.text && pdfData.text.trim().length > 0) {
  inputText = pdfData.text;
} else if (pdfData.data && typeof pdfData.data === 'string' && pdfData.data.trim().length > 0) {
  inputText = pdfData.data;
} else if (pdfData.content && pdfData.content.trim().length > 0) {
  inputText = pdfData.content;
}

// Validate that we actually have PDF content
if (!inputText || inputText.trim().length < 50) {
  throw new Error('PDF extraction failed - no valid text content extracted from the PDF file. Please ensure the PDF is not scanned/image-based and contains readable text.');
}

// Extract original filename from binary data for hotel name identification
let originalFileName = '';
try {
  const binaryInput = $input.first().binary;
  if (binaryInput) {
    const binaryKey = Object.keys(binaryInput)[0];
    if (binaryKey && binaryInput[binaryKey]) {
      originalFileName = binaryInput[binaryKey].fileName || '';
    }
  }
} catch(e) {}

// If no binary filename found, try from earlier nodes
if (!originalFileName) {
  try {
    const allItems = $input.all();
    for (const item of allItems) {
      if (item.binary) {
        const key = Object.keys(item.binary)[0];
        if (key && item.binary[key] && item.binary[key].fileName) {
          originalFileName = item.binary[key].fileName;
          break;
        }
      }
    }
  } catch(e) {}
}

console.log('PDF Text extracted, length:', inputText.length);
console.log('First 500 chars:', inputText.substring(0, 500));
console.log('Original filename:', originalFileName);

return [{
  json: {
    inputText: inputText.trim(),
    source: 'pdf',
    textLength: inputText.length,
    originalFileName: originalFileName
  }
}];

// Prepare input text from Webhook body (no binary/PDF)
// This node is called when no PDF file was uploaded

// Try to get text input from various possible locations
const json = $json;
const inputText = json.chatInput || json.text || json.body?.chatInput || json.body?.text || json.input || json.message || json.content || json.data || '';

if (!inputText || inputText.trim().length === 0) {
  // Provide helpful error message
  const availableKeys = Object.keys(json).filter(k => !k.startsWith('_')).join(', ');
  throw new Error('No input text provided. To extract hotel rates, either:\n1. Upload a PDF file containing rate data, OR\n2. Send JSON with a "text" or "chatInput" field containing the rate data.\n\nAvailable fields in request: [' + availableKeys + ']');
}

return [{
  json: {
    inputText: inputText.trim(),
    source: 'webhook_text'
  }
}];

// Prepare input text from Chat Trigger
const inputText = $json.chatInput || '';

if (!inputText || inputText.trim().length === 0) {
  throw new Error('No input text provided. Please provide hotel rate data to extract.');
}

return [{
  json: {
    inputText: inputText,
    source: 'chat_trigger'
  }
}];

// Parse AI extracted data and create common JSON format
// VERSION 10: Fixed child rate calculations and room category defaults
// Fixes: 1) Default room_category to "Standard" when null
//        2) PERCENTAGE_ON_SHARING_DOUBLE: childWithBed = childNoBed (no extra bed surcharge)
//        3) Default child policy: 50% of sharing double when no explicit policy for 6-12
//        4) Use Math.floor for half-rate calculations
//        5) Use base/cheapest room category double rate as reference for child calculations

const aiResponse = $input.first().json.message?.content || $input.first().json.text || '';

if (!aiResponse || aiResponse.trim().length === 0) {
  throw new Error('AI returned empty response. Please try again.');
}

let parsedData;
let jsonString = '';

try {
  let cleanedResponse = aiResponse.trim();
  try {
    parsedData = JSON.parse(cleanedResponse);
  } catch (directParseError) {
    const codeBlockMatch = cleanedResponse.match(/```(?:json)?\s*([\s\S]*?)```/i);
    if (codeBlockMatch && codeBlockMatch[1]) {
      jsonString = codeBlockMatch[1].trim();
      try { parsedData = JSON.parse(jsonString); } catch (codeBlockError) {}
    }
    if (!parsedData) {
      const firstBrace = cleanedResponse.indexOf('{');
      if (firstBrace !== -1) {
        let braceCount = 0, lastBrace = -1;
        for (let i = firstBrace; i < cleanedResponse.length; i++) {
          if (cleanedResponse[i] === '{') braceCount++;
          if (cleanedResponse[i] === '}') { braceCount--; if (braceCount === 0) { lastBrace = i; break; } }
        }
        if (lastBrace !== -1) {
          jsonString = cleanedResponse.substring(firstBrace, lastBrace + 1);
          try { parsedData = JSON.parse(jsonString); } catch (e) {}
        }
      }
    }
    if (!parsedData) {
      jsonString = cleanedResponse.replace(/^```(?:json)?\s*/gi, '').replace(/\s*```$/gi, '').replace(/^[^{]*/, '').replace(/[^}]*$/, '').trim();
      if (!jsonString.endsWith('}')) jsonString = jsonString + '}';
      try { parsedData = JSON.parse(jsonString); } catch (cleanError) {
        jsonString = jsonString.replace(/,\s*}/g, '}').replace(/,\s*]/g, ']').replace(/'/g, '"').replace(/([{,]\s*)(\w+)\s*:/g, '$1"$2":');
        try { parsedData = JSON.parse(jsonString); } catch (finalError) { throw new Error('Could not parse AI response as JSON.'); }
      }
    }
  }
} catch (e) {
  throw new Error('JSON parsing failed: ' + e.message);
}

if (parsedData.error) throw new Error('AI extraction error: ' + parsedData.error);

// ==================== NORMALIZE TO HOTELS ARRAY ====================
let hotels = [];
if (parsedData.hotels && Array.isArray(parsedData.hotels)) {
  hotels = parsedData.hotels;
} else if (parsedData.hotel_name || parsedData.rates) {
  hotels = [parsedData];
} else {
  throw new Error('Invalid data structure: expected hotels array or hotel data');
}

// ==================== DATE UTILITIES ====================
function parseDate(dateStr) {
  if (!dateStr) return null;
  if (/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(dateStr)) {
    const parts = dateStr.split('/');
    return new Date(parseInt(parts[2]), parseInt(parts[0]) - 1, parseInt(parts[1]));
  }
  if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
    const parts = dateStr.split('-');
    return new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
  }
  return new Date(dateStr);
}

function formatDateOutput(date) {
  if (!date) return null;
  return `${date.getMonth() + 1}/${date.getDate()}/${date.getFullYear()}`;
}

function addDays(date, days) {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
}

function isChristmasEve(date) { return date.getMonth() === 11 && date.getDate() === 24; }
function isNewYearsEve(date) { return date.getMonth() === 11 && date.getDate() === 31; }

function splitDateRangeForSupplements(startDate, endDate, hasChristmasSupplement, hasNYESupplement) {
  if (!hasChristmasSupplement && !hasNYESupplement) {
    return [{ start: startDate, end: endDate, isChristmasEve: false, isNewYearsEve: false }];
  }
  const segments = [];
  let current = new Date(startDate);
  let segmentStart = new Date(startDate);

  while (current <= endDate) {
    const isSpecialDate = (hasChristmasSupplement && isChristmasEve(current)) || (hasNYESupplement && isNewYearsEve(current));

    if (isSpecialDate) {
      if (segmentStart < current) {
        segments.push({ start: new Date(segmentStart), end: addDays(current, -1), isChristmasEve: false, isNewYearsEve: false });
      }
      segments.push({ 
        start: new Date(current), 
        end: new Date(current), 
        isChristmasEve: hasChristmasSupplement && isChristmasEve(current), 
        isNewYearsEve: hasNYESupplement && isNewYearsEve(current)
      });
      segmentStart = addDays(current, 1);
    } else if (current.getTime() === endDate.getTime()) {
      segments.push({ start: new Date(segmentStart), end: new Date(current), isChristmasEve: false, isNewYearsEve: false });
    }
    current = addDays(current, 1);
  }
  return segments.length > 0 ? segments : [{ start: startDate, end: endDate, isChristmasEve: false, isNewYearsEve: false }];
}

// ==================== PROCESS ALL HOTELS ====================
const allExpandedRates = [];
let globalRateId = 1;

hotels.forEach(hotel => {
  const hotelName = hotel.hotel_name || null;
  const baseMealPlan = hotel.base_meal_plan || 'BB';
  const availableMealPlans = hotel.available_meal_plans || ['BB', 'HB', 'FB'];
  const singleRatePercentage = hotel.single_rate_percentage || null;
  const rateType = hotel.rate_type || null;

  // Child policy
  let childPolicyType = hotel.child_policy_type || null;
  const childMealPercentage = hotel.child_meal_percentage || 0;
  let childRatePercentage = hotel.child_rate_percentage || 0;
  const childSupplements = hotel.child_supplements || {};
  const childSuppBB = childSupplements.bb || 0;
  const childSuppHB = childSupplements.hb || 0;
  const childSuppFB = childSupplements.fb || 0;
  const childSuppAI = childSupplements.ai || 0;
  const childSuppRO = childSupplements.ro || 0;
  const childSupplementIncludesBed = hotel.child_supplement_includes_bed || false;
  const childFreeMaxAge = hotel.child_free_max_age || 5;

  // DEFAULT CHILD POLICY: If no child policy is detected but we have a free age bracket,
  // default to 50% of sharing double (industry standard for Sri Lankan hotels)
  if (!childPolicyType && childFreeMaxAge > 0) {
    childPolicyType = 'PERCENTAGE_ON_SHARING_DOUBLE';
    childRatePercentage = 50;
    console.log('Applied default child policy: PERCENTAGE_ON_SHARING_DOUBLE at 50% for hotel:', hotelName);
  }

  // Additional occupancy rates (Dolphin Beach style)
  const additionalAdultRates = hotel.additional_adult_rates || {};
  const additionalChildRates = hotel.additional_child_rates || {};

  // Extra meals
  const extraMeals = hotel.extra_meals || {};
  const childBreakfast = extraMeals.child_breakfast || 0;
  const childLunch = extraMeals.child_lunch || 0;
  const childDinner = extraMeals.child_dinner || 0;
  const hasExtraMeals = childBreakfast > 0 || childLunch > 0 || childDinner > 0;

  // Charges
  const extraBedCharge = hotel.extra_bed_charge || 0;
  const thirdPersonSupplement = hotel.third_person_supplement || 0;
  const fourthPersonSupplement = hotel.fourth_person_supplement || 0;

  // Meal supplements
  const mealSupplements = hotel.meal_supplements || {};
  const bbToHbSupplement = mealSupplements.bb_to_hb_supplement || 0;
  const bbToFbSupplement = mealSupplements.bb_to_fb_supplement || 0;
  const hbToFbSupplement = mealSupplements.hb_to_fb_supplement || 0;
  const breakfastPrice = mealSupplements.breakfast_price || 0;
  const lunchPrice = mealSupplements.lunch_price || 0;
  const dinnerPrice = mealSupplements.dinner_price || 0;

  // Special supplements (Christmas Eve / New Year's Eve)
  const specialSupplements = hotel.special_supplements || {};
  const christmasEve = specialSupplements.christmas_eve || {};
  const newYearsEve = specialSupplements.new_years_eve || {};

  // Backward compat: simple supplement amounts
  const christmasEveSupplement = specialSupplements.christmas_eve_supplement || christmasEve.amount || 0;
  const newYearsEveSupplement = specialSupplements.new_years_eve_supplement || newYearsEve.amount || 0;
  const galaDinnerSupplement = specialSupplements.gala_dinner_supplement || 0;
  const galaDinnerChildPercentage = specialSupplements.gala_dinner_child_percentage || 50;

  // Determine if we have any Christmas/NYE supplements
  const hasChristmasSupplement = christmasEveSupplement > 0 || 
    (christmasEve.bb_adult > 0) || (christmasEve.hb_adult > 0) || (christmasEve.hb_fb_adult > 0) ||
    (christmasEve.bb_per_person > 0) || (christmasEve.hb_per_person > 0) ||
    (christmasEve.dinner_amount > 0) || (christmasEve.adult_amount > 0) ||
    (christmasEve.type && christmasEve.type !== 'NONE');

  const hasNYESupplement = newYearsEveSupplement > 0 || 
    (newYearsEve.bb_adult > 0) || (newYearsEve.hb_adult > 0) || (newYearsEve.hb_fb_adult > 0) ||
    (newYearsEve.bb_per_person > 0) || (newYearsEve.hb_per_person > 0) ||
    (newYearsEve.dinner_amount > 0) || (newYearsEve.adult_amount > 0) ||
    (newYearsEve.type && newYearsEve.type !== 'NONE');

  // Room supplements
  const roomSupplements = hotel.room_supplements || [];

  // Get rates
  const rates = hotel.rates || [];
  if (rates.length === 0) return;

  // ==================== BUILD DOUBLE RATE LOOKUP ====================
  // Needed for PERCENTAGE_ON_SHARING_DOUBLE child policy
  const doubleLookup = {};
  rates.forEach(rate => {
    const rt = (rate.room_type || '').toLowerCase();
    if (rt === 'double' || rt === 'twin') {
      const key = `${rate.room_category || 'Standard'}|${rate.meal_plan || ''}|${rate.start_date}|${rate.end_date}`;
      doubleLookup[key] = rate.price || 0;
    }
  });

  // ==================== BUILD BASE DOUBLE RATE LOOKUP ====================
  // Find the CHEAPEST double rate per meal plan per period (for child rate reference)
  const baseDoubleLookup = {};
  rates.forEach(rate => {
    const rt = (rate.room_type || '').toLowerCase();
    if (rt === 'double' || rt === 'twin') {
      const key = `${rate.meal_plan || ''}|${rate.start_date}|${rate.end_date}`;
      const price = rate.price || 0;
      if (!baseDoubleLookup[key] || price < baseDoubleLookup[key]) {
        baseDoubleLookup[key] = price;
      }
    }
  });

  // ==================== SPECIAL DATE SUPPLEMENT CALCULATOR ====================
  function getSpecialDateSupplement(suppConfig, mealPlan, occupancy) {
    if (!suppConfig || !suppConfig.type) return { adultSupplement: 0, childSupplement: 0 };

    const type = suppConfig.type;
    let adultPerPerson = 0;
    let childPerPerson = 0;
    const childPct = (suppConfig.child_percentage || 50) / 100;

    switch (type) {
      case 'SIMPLE_PER_PERSON':
        adultPerPerson = suppConfig.amount || 0;
        childPerPerson = Math.round(adultPerPerson * childPct);
        break;

      case 'BASIS_SPECIFIC':
        if (suppConfig.bb_per_person > 0 || suppConfig.hb_per_person > 0 || suppConfig.fb_per_person > 0) {
          if (mealPlan === 'BB' || mealPlan === 'RO') {
            adultPerPerson = suppConfig.bb_per_person || 0;
          } else if (mealPlan === 'HB') {
            adultPerPerson = suppConfig.hb_per_person || suppConfig.bb_per_person || 0;
          } else if (mealPlan === 'FB' || mealPlan === 'AI') {
            adultPerPerson = suppConfig.fb_per_person || suppConfig.hb_per_person || suppConfig.bb_per_person || 0;
          } else {
            adultPerPerson = suppConfig.bb_per_person || 0;
          }
          childPerPerson = Math.round(adultPerPerson * childPct);
        }
        else if (suppConfig.bb_adult > 0 || suppConfig.hb_adult > 0 || suppConfig.hb_fb_adult > 0) {
          if (mealPlan === 'BB' || mealPlan === 'RO') {
            adultPerPerson = suppConfig.bb_adult || 0;
          } else if (mealPlan === 'HB') {
            adultPerPerson = suppConfig.hb_adult || suppConfig.hb_fb_adult || 0;
          } else if (mealPlan === 'FB' || mealPlan === 'AI') {
            adultPerPerson = suppConfig.fb_adult || suppConfig.hb_fb_adult || suppConfig.hb_adult || 0;
          } else {
            adultPerPerson = suppConfig.bb_adult || 0;
          }
          childPerPerson = Math.round(adultPerPerson * childPct);
        }
        break;

      case 'COMPULSORY_SUPPLEMENT':
        adultPerPerson = suppConfig.amount || 0;
        childPerPerson = Math.round(adultPerPerson * childPct);
        break;

      case 'DINNER_SUPPLEMENT':
        adultPerPerson = suppConfig.dinner_amount || 0;
        childPerPerson = Math.round(adultPerPerson * childPct);
        break;

      case 'GALA_DINNER':
        adultPerPerson = suppConfig.adult_amount || 0;
        const galaPct = (suppConfig.child_percentage || 50) / 100;
        childPerPerson = Math.round(adultPerPerson * galaPct);
        break;

      default:
        adultPerPerson = suppConfig.amount || 0;
        childPerPerson = Math.round(adultPerPerson * childPct);
    }

    return {
      adultSupplement: adultPerPerson * occupancy,
      childSupplement: childPerPerson
    };
  }

  // ==================== CHILD PRICE CALCULATION ====================
  function getChildPrices(mealPlan, contractChildRate, roomPrice, occupancy, roomCategory, startDate, endDate) {
    let childNoBed = 0;
    let childWithBed = 0;

    // TYPE A: Percentage on meals (Winchester, Athgira, Zest)
    if (childPolicyType === 'PERCENTAGE_ON_MEALS' && childMealPercentage > 0) {
      const percentage = childMealPercentage / 100;
      if (mealPlan === 'RO') {
        childNoBed = 0;
      } else if (mealPlan === 'BB') {
        childNoBed = Math.round(breakfastPrice * percentage);
      } else if (mealPlan === 'HB') {
        childNoBed = Math.round(breakfastPrice * percentage) + Math.round(dinnerPrice * percentage);
      } else if (mealPlan === 'FB') {
        childNoBed = Math.round(breakfastPrice * percentage) + Math.round(lunchPrice * percentage) + Math.round(dinnerPrice * percentage);
      } else if (mealPlan === 'AI') {
        childNoBed = Math.round(breakfastPrice * percentage) + Math.round(lunchPrice * percentage) + Math.round(dinnerPrice * percentage);
      }
      childWithBed = childNoBed + extraBedCharge;
      return { childNoBed, childWithBed };
    }

    // TYPE B: Percentage on per person rate (Blue Whale)
    if (childPolicyType === 'PERCENTAGE_ON_RATE' && childRatePercentage > 0) {
      const percentage = childRatePercentage / 100;
      const perPersonRate = occupancy > 0 ? roomPrice / occupancy : roomPrice;
      childNoBed = Math.floor(perPersonRate * percentage);
      childWithBed = childNoBed + extraBedCharge;
      return { childNoBed, childWithBed };
    }

    // TYPE C: Percentage on sharing double rate (Earl's Reef, Rajarata, Lavanga "Half Rate")
    // FIXED: Use base (cheapest) double rate as reference and don't add extra bed charge
    if (childPolicyType === 'PERCENTAGE_ON_SHARING_DOUBLE' && childRatePercentage > 0) {
      const percentage = childRatePercentage / 100;

      // First try: look up double rate for same room category, meal plan, period
      const lookupKey = `${roomCategory || 'Standard'}|${mealPlan}|${startDate}|${endDate}`;
      let referenceDoubleRate = doubleLookup[lookupKey];

      // Fallback: use the CHEAPEST double rate for this meal plan and period
      if (!referenceDoubleRate) {
        const baseKey = `${mealPlan}|${startDate}|${endDate}`;
        referenceDoubleRate = baseDoubleLookup[baseKey];
      }

      // Final fallback: use current room price
      if (!referenceDoubleRate) {
        referenceDoubleRate = roomPrice;
      }

      childNoBed = Math.floor(referenceDoubleRate * percentage);
      // FIXED: For "Half Rate" / sharing double percentage policy,
      // Child With Bed = Child With No Bed (extra bed not added to child rate)
      childWithBed = childNoBed;
      return { childNoBed, childWithBed };
    }

    // TYPE D: Child supplements by meal plan (Maalu Maalu)
    if (childPolicyType === 'CHILD_SUPPLEMENTS_BY_MEAL') {
      if (mealPlan === 'RO') childNoBed = childSuppRO;
      else if (mealPlan === 'BB') childNoBed = childSuppBB;
      else if (mealPlan === 'HB') childNoBed = childSuppHB;
      else if (mealPlan === 'FB') childNoBed = childSuppFB;
      else if (mealPlan === 'AI') childNoBed = childSuppAI || childSuppFB;
      else childNoBed = childSuppBB;
      childWithBed = childSupplementIncludesBed ? childNoBed : childNoBed + extraBedCharge;
      return { childNoBed: Math.round(childNoBed), childWithBed: Math.round(childWithBed) };
    }

    // TYPE E: Extra meals table (Citrus style)
    if (childPolicyType === 'EXTRA_MEALS_TABLE' || hasExtraMeals) {
      if (mealPlan === 'RO') childNoBed = 0;
      else if (mealPlan === 'BB') childNoBed = childBreakfast;
      else if (mealPlan === 'HB') childNoBed = childBreakfast + childDinner;
      else if (mealPlan === 'FB') childNoBed = childBreakfast + childLunch + childDinner;
      else if (mealPlan === 'AI') childNoBed = childBreakfast + childLunch + childDinner;
      childWithBed = childNoBed + extraBedCharge;
      return { childNoBed: Math.round(childNoBed), childWithBed: Math.round(childWithBed) };
    }

    // TYPE F: Additional occupancy (Dolphin Beach)
    if (childPolicyType === 'ADDITIONAL_OCCUPANCY') {
      const childRates = additionalChildRates || {};
      if (mealPlan === 'RO') childNoBed = childRates.ro || 0;
      else if (mealPlan === 'BB') childNoBed = childRates.bb || 0;
      else if (mealPlan === 'HB') childNoBed = childRates.hb || 0;
      else if (mealPlan === 'FB') childNoBed = childRates.fb || 0;
      else if (mealPlan === 'AI') childNoBed = childRates.ai || childRates.fb || 0;
      else childNoBed = childRates.bb || 0;
      childWithBed = childNoBed; // Additional occupancy already includes bed
      return { childNoBed: Math.round(childNoBed), childWithBed: Math.round(childWithBed) };
    }

    // TYPE G: Child rate in rate table
    if (childPolicyType === 'CHILD_RATE_TABLE' && contractChildRate > 0) {
      childNoBed = contractChildRate;
      childWithBed = contractChildRate;
      return { childNoBed: Math.round(childNoBed), childWithBed: Math.round(childWithBed) };
    }

    // TYPE H: No children policy (Santani)
    if (childPolicyType === 'NO_CHILDREN') {
      return { childNoBed: 0, childWithBed: 0 };
    }

    // Default: use contract child rate if available
    if (contractChildRate > 0) {
      return { childNoBed: Math.round(contractChildRate), childWithBed: Math.round(contractChildRate) };
    }

    return { childNoBed: 0, childWithBed: 0 };
  }

  // ==================== PROCESS RATES ====================
  const mealPlanMap = { 'RO': 0, 'BB': 1, 'HB': 2, 'FB': 3, 'AI': 4, 'WI': 5 };

  rates.forEach(rate => {
    // FIXED: Default room_category to "Standard" when not provided
    const roomCategory = rate.room_category || 'Standard';
    const roomType = rate.room_type ? rate.room_type.charAt(0).toUpperCase() + rate.room_type.slice(1).toLowerCase() : 'Double';
    const mealPlan = rate.meal_plan || baseMealPlan;
    const ratePrice = rate.price || 0;
    const contractChildRate = rate.child_rate || 0;
    const market = rate.market || hotel.market || 'All Market';
    const special = rate.special || 'N';
    const entryRateType = rate.rate_type || rateType || null;

    const origStartDate = parseDate(rate.start_date);
    const origEndDate = parseDate(rate.end_date);
    if (!origStartDate || !origEndDate) return;

    // Room type details
    let roomTypeId = 2;
    let occupancy = 2;
    if (roomType === 'Single') { roomTypeId = 1; occupancy = 1; }
    else if (roomType === 'Double' || roomType === 'Twin') { roomTypeId = 2; occupancy = 2; }
    else if (roomType === 'Triple') { roomTypeId = 3; occupancy = 3; }
    else if (roomType === 'Quadruple' || roomType === 'Family') { roomTypeId = 4; occupancy = 4; }

    // Get meal plan ID
    const mealId = mealPlanMap[mealPlan] !== undefined ? mealPlanMap[mealPlan] : 1;

    // Split date range for special supplements
    const dateSegments = splitDateRangeForSupplements(origStartDate, origEndDate, hasChristmasSupplement, hasNYESupplement);

    dateSegments.forEach(segment => {
      const startDate = formatDateOutput(segment.start);
      const endDate = formatDateOutput(segment.end);

      // Calculate final price
      let finalPrice = ratePrice;
      let adultSupplement = 0;
      let childSupplement = 0;

      // Add special date supplements using the new typed system
      if (segment.isChristmasEve) {
        const supp = getSpecialDateSupplement(christmasEve, mealPlan, occupancy);
        if (supp.adultSupplement > 0) {
          finalPrice += supp.adultSupplement;
          childSupplement = supp.childSupplement;
        } else if (christmasEveSupplement > 0) {
          finalPrice += christmasEveSupplement * occupancy;
          childSupplement = Math.round(christmasEveSupplement * (galaDinnerChildPercentage / 100));
        }
      } else if (segment.isNewYearsEve) {
        const supp = getSpecialDateSupplement(newYearsEve, mealPlan, occupancy);
        if (supp.adultSupplement > 0) {
          finalPrice += supp.adultSupplement;
          childSupplement = supp.childSupplement;
        } else if (newYearsEveSupplement > 0) {
          finalPrice += newYearsEveSupplement * occupancy;
          childSupplement = Math.round(newYearsEveSupplement * (galaDinnerChildPercentage / 100));
        }
      }

      // Get child prices
      const childPrices = getChildPrices(mealPlan, contractChildRate, ratePrice, occupancy, roomCategory, rate.start_date, rate.end_date);
      let childNoBed = childPrices.childNoBed;
      let childWithBed = childPrices.childWithBed;

      // Add special date child supplements
      if (childSupplement > 0) {
        childNoBed += childSupplement;
        childWithBed += childSupplement;
      }

      // Build hotel display name with rate type if applicable
      let displayHotel = hotelName;

      allExpandedRates.push({
        id: globalRateId++,
        start_date: startDate,
        end_date: endDate,
        meal: mealPlan,
        meal_id: mealId,
        hotel: displayHotel,
        price: Math.round(finalPrice),
        child_with_bed: childWithBed,
        child_with_no_bed: childNoBed,
        room_type: roomType,
        room_type_id: roomTypeId,
        room_category: roomCategory,
        room_category_id: null,
        market: market,
        special: special,
        rate_type: entryRateType
      });
    });
  });
});

