  const hotelB = (b.hotel || '').toString().toLowerCase();
  if (hotelA !== hotelB) return hotelA.localeCompare(hotelB);

  // 1. Sort by Start Date
  const startDateA = parseDate(a.start_date);
  const startDateB = parseDate(b.start_date);
  if (startDateA.getTime() !== startDateB.getTime()) return startDateA.getTime() - startDateB.getTime();

  // 2. Sort by End Date
  const endDateA = parseDate(a.end_date);
  const endDateB = parseDate(b.end_date);
  if (endDateA.getTime() !== endDateB.getTime()) return endDateA.getTime() - endDateB.getTime();

  // 3. Sort by Room Category
  const roomCatA = (a.room_category || '').toString().toLowerCase();
  const roomCatB = (b.room_category || '').toString().toLowerCase();
  if (roomCatA !== roomCatB) return roomCatA.localeCompare(roomCatB);

  // 4. Sort by Meal ID
  const mealIdA = a.meal_id || 0;
  const mealIdB = b.meal_id || 0;
  if (mealIdA !== mealIdB) return mealIdA - mealIdB;

  // 5. Sort by Room Type ID
  const roomTypeIdA = a.room_type_id || 0;
  const roomTypeIdB = b.room_type_id || 0;
  return roomTypeIdA - roomTypeIdB;
});

