// ==================== HELPER FUNCTIONS ====================

function formatDate(d) {
  if (!d) return '';
  // Try as object with getTime (Date-like, avoids instanceof across VM contexts)
  if (typeof d === 'object' && d !== null && typeof d.getTime === 'function') {
    const t = d.getTime();
    if (isNaN(t)) return '';
    const dd2 = String(d.getUTCDate()).padStart(2, '0');
    const mm2 = String(d.getUTCMonth() + 1).padStart(2, '0');
    const yy2 = d.getUTCFullYear();
    return dd2 + '.' + mm2 + '.' + yy2;
  }
  // Excel serial number
  if (typeof d === 'number' && d > 40000 && d < 60000) {
    const date = new Date((d - 25569) * 86400000);
    if (isNaN(date.getTime())) return '';
    return String(date.getUTCDate()).padStart(2,'0') + '.' + String(date.getUTCMonth()+1).padStart(2,'0') + '.' + date.getUTCFullYear();
  }
  // String
  const s = String(d).trim();
  if (!s) return '';
  // ISO YYYY-MM-DD
  const isoMatch = s.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (isoMatch) return isoMatch[3] + '.' + isoMatch[2] + '.' + isoMatch[1];
  // Try parsing
  const date = new Date(s);
  if (isNaN(date.getTime())) return '';
  return String(date.getUTCDate()).padStart(2,'0') + '.' + String(date.getUTCMonth()+1).padStart(2,'0') + '.' + date.getUTCFullYear();
}

function isValidDate(val) {
  if (!val) return false;
  // Date-like object (avoid instanceof across VM contexts)
  if (typeof val === 'object' && val !== null && typeof val.getTime === 'function') return !isNaN(val.getTime());
  if (typeof val === 'number' && val > 40000 && val < 60000) return true;
  if (typeof val === 'number') return false;
  const s = String(val).trim();
  if (!s) return false;
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return true;
  if (/^\d{1,2}[\/\.-]\d{1,2}[\/\.-]\d{2,4}/.test(s)) return true;
  if (/middle|high|low|peak/i.test(s)) return false;
  const d = new Date(s);
  return !isNaN(d.getTime()) && d.getFullYear() > 2000;
}

function parseChildPolicies(policies) {
  // Extract child rates from tiered age-based policies
  // childNoBed = sharing bed / no extra bed rate (younger children)
  // childBed = extra bed / above age rate (older children)
  let childNoBed = 0, childBed = 0;
  const priced = []; // collect all entries with a price

  for (const policy of policies) {
    const p = policy.trim();
    if (!p) continue;

    // Skip adult entries
    if (/=\s*adult/i.test(p) || /adult\s*rate/i.test(p)) continue;

    // Check FOC entries (free of charge)
    const isFOC = /FOC|free\s*of\s*charge/i.test(p);
    if (isFOC) continue; // skip FOC - we want actual prices

    // Try to extract a price from this entry
    let price = 0;
    // Pattern: number followed by USD/$/usd or preceded by USD/$/usd
    let m = p.match(/(\d+(?:[.,]\d+)?)\s*(?:USD|\$|usd)/i);
    if (!m) m = p.match(/(?:USD|\$|usd)\s*(\d+(?:[.,]\d+)?)/i);
    // Pattern: surcharge/charge number
    if (!m) m = p.match(/(?:surcharge|charge)\s+(\d+(?:[.,]\d+)?)/i);
    // Pattern: colon then number (e.g. "6-10 yrs: 8.5")
    if (!m) m = p.match(/:\s*(\d+(?:[.,]\d+)?)/);
    // Pattern: just a number after age range (e.g. "6-9 yrs: 8.5$")
    if (!m) m = p.match(/(?:yrs|years?).*?(\d+(?:[.,]\d+)?)/i);

    if (m) {
      price = parseFloat(m[1].replace(',', '.'));
      if (price > 0 && price < 500) { // sanity check
        const isAbove = /^\s*(?:>|above|&\s*above|\d+\s*&\s*above)/i.test(p);
        const isExtraBed = /extra\s*bed/i.test(p);
        priced.push({ price, isAbove, isExtraBed, text: p });
      }
    }
  }

  if (priced.length === 0) return { childNoBed: 0, childBed: 0 };

  if (priced.length === 1) {
    // Single rate = childNoBed (sharing bed / no extra bed)
    if (priced[0].isAbove || priced[0].isExtraBed) {
      childBed = priced[0].price;
    } else {
      childNoBed = priced[0].price;
    }
  } else {
    // Multiple rates: lower price = childNoBed (younger/sharing), higher = childBed (older/extra bed)
    priced.sort((a, b) => a.price - b.price);
    childNoBed = priced[0].price;
    childBed = priced[priced.length - 1].price;
  }

  return { childNoBed, childBed };
}


// =============================================
// PEAK SEASON SURCHARGE: Parse surcharge dates and amounts
// =============================================
function parseSurchargeAmount(text) {
  if (!text) return { amount: 0, isPercent: false };
  // Strip leading dashes/bullets
  text = text.replace(/^[-–—•+]\s*/, '');
  // "Surcharge 11.76$/room/night"
  let m = text.match(/surcharge\s+([\d.,]+)\s*\$/i);
  if (m) return { amount: parseFloat(m[1].replace(',','.')), isPercent: false };
  // "Surcharge 20%/room/night"
  m = text.match(/surcharge\s+([\d.,]+)\s*%/i);
  if (m) return { amount: parseFloat(m[1].replace(',','.')), isPercent: true };
  // "Surcharge not exceeding 50%"
  m = text.match(/surcharge.*?([\d.,]+)\s*%/i);
  if (m) return { amount: parseFloat(m[1].replace(',','.')), isPercent: true };
  // "Surcharge X USD/room"
  m = text.match(/surcharge\s+([\d.,]+)\s*USD/i);
  if (m) return { amount: parseFloat(m[1].replace(',','.')), isPercent: false };
  return { amount: 0, isPercent: false };
}

function parsePeakDates(texts, contractYear) {
  const peaks = [];
  const yr = contractYear || 2026;

  function addPeak(d1, m1, y1, d2, m2, y2) {
    if (d1 < 1 || d1 > 31 || m1 < 1 || m1 > 12) return;
    if (d2 < 1 || d2 > 31 || m2 < 1 || m2 > 12) return;
    peaks.push({ 
      start: new Date(Date.UTC(y1, m1 - 1, d1)), 
      end: new Date(Date.UTC(y2, m2 - 1, d2)) 
    });
  }

  function serialToDate(serial) {
    if (typeof serial !== 'number' || serial < 40000) return null;
    return new Date((serial - 25569) * 86400000);
  }

  for (const text of texts) {
    if (!text) continue;
    const t = String(text);

    // Skip header/label rows, fireworks-related texts, and death anniversary dates
    if (/^(PEAK|surcharge|local|update)/i.test(t.trim())) continue;
    // Skip "Hung King's death anniversary" - the date in parens is NOT the holiday surcharge date
    if (/hung\s+king.*death\s+anniversary/i.test(t)) continue;
    // (removed month-name-start skip)
    // Skip fireworks and special event surcharge lines
    if (/firework|qualifying\s+round|final\s+night/i.test(t)) continue;
    if (/^[+]\s*surcharge/i.test(t.trim())) continue;
    if (/^Da\s+Nang|^-\s*Da\s+Nang/i.test(t.trim())) continue;

    // Handle serial number dates (e.g., "46023")
    const serialMatch = t.match(/^(\d{5})$/);
    if (serialMatch) {
      const dt = serialToDate(parseInt(serialMatch[1]));
      if (dt) peaks.push({ start: dt, end: dt });
      continue;
    }

    // Normalize separators: replace & with ;, replace multiple dashes/em-dashes
    let norm = t.replace(/\s*&\s*/g, '; ').replace(/[–—]/g, '-');

    // Split by semicolons for multiple dates in one line
    const parts = norm.split(/[;,]/);

    for (let part of parts) {
      part = part.trim();
      if (!part) continue;

      // Pattern 1: DD/MM/YYYY - DD/MM/YYYY (date range with full dates)
      let m = part.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})\s*-\s*(\d{1,2})\/(\d{1,2})\/(\d{4})/);
      if (m) {
        addPeak(parseInt(m[1]), parseInt(m[2]), parseInt(m[3]),
                parseInt(m[4]), parseInt(m[5]), parseInt(m[6]));
        continue;
      }

      // Pattern 2: DD/MM - DD/MM/YYYY (range, first date no year)
      m = part.match(/(\d{1,2})\/(\d{1,2})\s*-\s*(\d{1,2})\/(\d{1,2})\/(\d{4})/);
      if (m) {
        const y = parseInt(m[5]);
        addPeak(parseInt(m[1]), parseInt(m[2]), y,
                parseInt(m[3]), parseInt(m[4]), y);
        continue;
      }

      // Pattern 3: DD-DD/MM/YYYY (range within same month)
      m = part.match(/(\d{1,2})\s*-\s*(\d{1,2})\/(\d{1,2})\/(\d{4})/);
      if (m) {
        addPeak(parseInt(m[1]), parseInt(m[3]), parseInt(m[4]),
                parseInt(m[2]), parseInt(m[3]), parseInt(m[4]));
        continue;
      }

      // Pattern 4: DD/MM/YYYY (single date)
      m = part.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
      if (m) {
        addPeak(parseInt(m[1]), parseInt(m[2]), parseInt(m[3]),
                parseInt(m[1]), parseInt(m[2]), parseInt(m[3]));
        continue;
      }

      // Pattern 5: DD/MM (no year, use contract year)
      m = part.match(/(\d{1,2})\/(\d{1,2})(?:[^/\d]|$)/);
      if (m) {
        addPeak(parseInt(m[1]), parseInt(m[2]), yr,
                parseInt(m[1]), parseInt(m[2]), yr);
        continue;
      }
      // Pattern 6: "DD Month" or "DD, DD Month" (e.g., "02 Sep", "24, 31 Dec")
      const monthNames = {'jan':1,'feb':2,'mar':3,'apr':4,'may':5,'jun':6,'jul':7,'aug':8,'sep':9,'oct':10,'nov':11,'dec':12};
      const mnMatch = part.match(/(\d{1,2})(?:[,\s]+(?:and\s+)?(\d{1,2}))?\s+(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)/i);
      if (mnMatch) {
        const mm = monthNames[mnMatch[3].toLowerCase().substring(0, 3)];
        if (mm) {
          addPeak(parseInt(mnMatch[1]), mm, yr, parseInt(mnMatch[1]), mm, yr);
          if (mnMatch[2]) {
            addPeak(parseInt(mnMatch[2]), mm, yr, parseInt(mnMatch[2]), mm, yr);
          }
        }
        continue;
      }
      // Pattern 7: "Month DD" / "Month DD-DD" / "Month DD- Month DD"
      const mn7Names = {'jan':1,'feb':2,'mar':3,'apr':4,'may':5,'jun':6,'jul':7,'aug':8,'sep':9,'oct':10,'nov':11,'dec':12};
      const mn7 = part.match(/(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\w*\s+(\d{1,2})(?:\s*-\s*(?:(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\w*\s+)?(\d{1,2}))?/i);
      if (mn7) {
        const m1 = mn7Names[mn7[1].toLowerCase().substring(0,3)];
        const d1 = parseInt(mn7[2]);
        if (m1 && d1) {
          if (mn7[4]) {
            const m2 = mn7[3] ? mn7Names[mn7[3].toLowerCase().substring(0,3)] : m1;
            const d2 = parseInt(mn7[4]);
            if (m2 && d2) addPeak(d1, m1, yr, d2, m2, yr);
          } else {
            addPeak(d1, m1, yr, d1, m1, yr);
          }
        }
        continue;
      }
    }
  }

  // Add Dec 24 and Dec 31 peaks based on whether surcharge texts explicitly mention them
  const hasExplicitDec24 = peaks.some(p => p.start.getUTCMonth() === 11 && p.start.getUTCDate() === 24);
  const hasExplicitDec31 = peaks.some(p => p.start.getUTCMonth() === 11 && p.start.getUTCDate() === 31);
  const mentionsDec24 = texts.some(t => /24\/12|24\.12|christmas.*24|24.*dec/i.test(t));
  const mentionsDec31 = texts.some(t => /31\/12|31\.12|31.*dec|dec.*31|new\s*year|year.?end/i.test(t));
  const isVNHolidayOnly = texts.some(t => /vietnamese\s+national/i.test(t));
  // Auto-add Dec 24 if not already parsed and not VN-only holidays
  if (!hasExplicitDec24 && !isVNHolidayOnly) {
    const dec24 = new Date(Date.UTC(yr, 11, 24));
    const dec25 = new Date(Date.UTC(yr, 11, 25));
    peaks.push({ start: dec24, end: dec25 });
  }
  // Auto-add Dec 31 only if surcharge texts don't already explicitly handle Dec dates
  // (if they explicitly mention Dec 24 but NOT Dec 31, don't auto-add Dec 31)
  if (!hasExplicitDec31 && !isVNHolidayOnly && !mentionsDec24) {
    const dec31 = new Date(Date.UTC(yr, 11, 31));
    const jan1 = new Date(Date.UTC(yr + 1, 0, 1));
    peaks.push({ start: dec31, end: jan1 });
  }

  // Sort and merge overlapping
  peaks.sort((a, b) => a.start - b.start);
  const merged = [];
  for (const p of peaks) {
    if (merged.length > 0) {
      const last = merged[merged.length - 1];
      if (p.start <= new Date(last.end.getTime() + 86400000)) {
        last.end = new Date(Math.max(last.end.getTime(), p.end.getTime()));
        continue;
      }
    }
    merged.push({ start: new Date(p.start), end: new Date(p.end) });
  }

  return merged;
}

function splitDateRangeByPeaks(startStr, endStr, peakDates) {
  // Split a date range (DD.MM.YYYY strings) into sub-ranges of peak and non-peak periods
  // Returns array of { start: string, end: string, isPeak: boolean }
  if (!peakDates || peakDates.length === 0) {
    return [{ start: startStr, end: endStr, isPeak: false }];
  }

  // Parse DD.MM.YYYY to Date
  function parseDate(s) {
    if (!s) return null;
    const parts = String(s).split('.');
    if (parts.length !== 3) return null;
    return new Date(Date.UTC(parseInt(parts[2]), parseInt(parts[1])-1, parseInt(parts[0])));
  }
  function dateToStr(d) {
    return String(d.getUTCDate()).padStart(2,'0') + '.' + 
           String(d.getUTCMonth()+1).padStart(2,'0') + '.' + 
           d.getUTCFullYear();
  }
  function addDays(d, n) { return new Date(d.getTime() + n * 86400000); }

  const rangeStart = parseDate(startStr);
  const rangeEnd = parseDate(endStr);
  if (!rangeStart || !rangeEnd || rangeStart > rangeEnd) {
    return [{ start: startStr, end: endStr, isPeak: false }];
  }

  const segments = [];
  let cur = new Date(rangeStart);

  for (const peak of peakDates) {
    // Skip peaks outside our range
    if (peak.end < rangeStart || peak.start > rangeEnd) continue;

    const peakStart = peak.start < rangeStart ? rangeStart : peak.start;
    // Allow peak to extend 1 day beyond rangeEnd (e.g., Dec 31 → Jan 1)
    const peakEnd = peak.end > addDays(rangeEnd, 1) ? rangeEnd : peak.end;

    // Non-peak before this peak
    if (cur < peakStart) {
      segments.push({ start: dateToStr(cur), end: dateToStr(addDays(peakStart, -1)), isPeak: false });
    }

    // Peak segment
    segments.push({ start: dateToStr(peakStart), end: dateToStr(peakEnd), isPeak: true });
    cur = addDays(peakEnd, 1);
  }

  // Remaining non-peak after last peak
  if (cur <= rangeEnd) {
    segments.push({ start: dateToStr(cur), end: dateToStr(rangeEnd), isPeak: false });
  }

  return segments.length > 0 ? segments : [{ start: startStr, end: endStr, isPeak: false }];
}

function parseRoomCategory(roomTypeStr) {
  let cat = roomTypeStr;
  cat = cat.replace(/\s*\(Bed\s*type:[^)]*\)/gi, '');
  cat = cat.replace(/\s*\([^)]*(?:Double|Twin|Triple|double|twin|triple)[^)]*\)/gi, '');
  cat = cat.replace(/\b(?:DBL|TWN|TPL|SGL)\s*(?:\/\s*(?:DBL|TWN|TPL|SGL))?\b/gi, '');
  cat = cat.replace(/\bDouble\b/gi, ''); cat = cat.replace(/\bTwin\b/gi, '');
  cat = cat.replace(/\bTriple\b/gi, ''); cat = cat.replace(/\bSingle\b/gi, '');
  cat = cat.replace(/\bRoom\b/gi, '');
  cat = cat.replace(/\s*\/\s*/g, ' '); cat = cat.replace(/\s+/g, ' ').trim();
  cat = cat.replace(/\s*\([^)]*\)/g, '').trim(); // Strip ALL remaining parentheticals
  cat = cat.replace(/^[\s\-\/]+|[\s\-\/]+$/g, '').trim();
  if (!cat) cat = 'Standard';
  return cat;
}

function getMealId(c) { return {1:'BB',2:'HB',3:'FB',4:'AI',5:'RO'}[c] || 'BB'; }

function isHotelNote(hv) {
  const lower = hv.toLowerCase().trim();
  if (hv.startsWith('Total:') || hv.startsWith('(')) return true;
  if (lower.includes('room rates include') || lower.includes('room rates do not')) return true;
  if (lower.includes('room rate inclusion') || lower.includes('room rate exclusion')) return true;
  if (lower.includes('temporarily') || lower.includes('former name')) return true;
  if (lower.startsWith('includes') || lower.startsWith('not include') || lower.startsWith('services')) return true;
  if (lower.startsWith('note:') || lower.startsWith('note ')) return true;
  if (lower.startsWith('check-in') || lower.startsWith('check-out') || lower.startsWith('check in') || lower.startsWith('check out')) return true;
  if (lower.includes('room only') || lower.includes('no breakfast') || lower.includes('no water')) return true;
  if (lower.includes('not include breakfast')) return true;
  if (lower.startsWith('surcharge') || lower.startsWith('extra bed') || lower.startsWith('child')) return true;
  if (/^(bb|hb|fb|ro|ai)\b/i.test(hv)) return true;
  if (/^\d+\s*%/i.test(hv)) return true;
  if (/^room\s*\d+\s*pax/i.test(hv)) return true;
  if (/^room\s+rate/i.test(hv)) return true;
  if (/USD\/person/i.test(hv)) return true;
  if (/^\d+:\d+\s*(am|pm)/i.test(hv)) return true;
  if (/^(inclusion|exclusion|included|excluded)/i.test(hv)) return true;
  if (/^free\b/i.test(hv)) return true;
  if (/^(breakfast|lunch|dinner|meal)/i.test(hv)) return true;
  if (/^(compulsory|mandatory|supplement)/i.test(hv)) return true;
  if (/^(tax|service charge|vat)/i.test(hv)) return true;
  if (/^[\d.,]+\s*USD/i.test(hv)) return true;
  if (/^<\s*\d+/i.test(hv)) return true;
  if (/^\d+\s*-\s*\d+\s*(yrs|years|y\.o)/i.test(hv)) return true;
  if (/^price\s+incl/i.test(hv)) return true;
  if (/^(tea|coffee|mineral|water|wifi|shuttle|transfer|pool|spa|gym|parking)/i.test(hv)) return true;
  if (/^(welcome|complimentary|daily|early|late)/i.test(hv)) return true;
  if (/^(cancellation|no show|no-show|penalty|deposit)/i.test(hv)) return true;
  if (/^(valid|validity|applicable|apply|applied)/i.test(hv)) return true;
  if (/^(peak|high|low)\s*(season|period)/i.test(hv)) return true;
  if (/^(min|max|minimum|maximum)\s*\d/i.test(hv)) return true;
  if (/\bUSD\s*\/\s*(person|pax|room|night)/i.test(hv)) return true;
  if (/^(rate|price)\s+(incl|excl|include|exclude|for|per)/i.test(hv)) return true;
  if (/^(in|ex)clud(e|ing|ed)/i.test(hv)) return true;
  // Lines starting with dash/bullet (notes, inclusions, exclusions)
  if (/^[-–—•]\s/.test(hv)) return true;
  // "Price includes/excludes" notes
  if (/^prices+(include|exclude|incl|excl)/i.test(hv)) return true;
  // "Total: X rooms" type notes
  if (/^totals*:/i.test(hv)) return true;
  // Lines with "not valid" 
  if (/nots+valid/i.test(hv)) return true;
  // Lines starting with numbers followed by text (e.g., "01 bottle of mineral water")
  if (/^0ds/.test(hv)) return true;
  // Lines with "complimentary" or "swimming pool" etc.
  if (/complimentary|swimmings*pool|internets*access|minerals*water/i.test(hv)) return true;
  // Date-list notes (e.g., "Jan 01; 16-20 Feb; 26 Apr; 30 Apr; 02 Sep")
  if (/^\d{1,2}[,;\s]/.test(hv) && /\b(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\b/i.test(hv)) return true;
  if (/\b(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\s+\d/i.test(hv) && /[;,]/.test(hv) && hv.length < 80) return true;
  // Firework/festival notes
  if (/firework|festival/i.test(hv)) return true;
  if (/^promotion\b/i.test(hv)) return true;
  return false;
}

// ==================== MAIN PROCESSING ====================

const outputRows = [];

for (let si = 0; si < dataSheets.length; si++) {
  const sheetName = dataSheets[si];
  if (si > 0) await new Promise(resolve => setTimeout(resolve, 0));

  const ws = workbook.Sheets[sheetName];
  const rawData = ws; // Already 2D array from readWorkbook
  if (!rawData || rawData.length < 3) continue;

  // ---- DETECT COLUMN LAYOUT ----
  let usdStartCol = -1, headerRowIdx = -1, colHeaderRowIdx = -1;
  for (let r = 0; r < Math.min(10, rawData.length); r++) {
    const row = rawData[r] || [];
    for (let c = 0; c < row.length; c++) {
      const val = String(row[c] || '').toUpperCase().trim();
      if (val.includes('RATES IN USD') || val.includes('ROOM RATES IN USD')) {
        usdStartCol = c; headerRowIdx = r; break;
      }
    }
    if (usdStartCol !== -1) break;
  }
  if (usdStartCol === -1) {
  diag.push('Sheet ' + sheetName + ': No RATES IN USD found');
  continue;
}
diag.push('Sheet ' + sheetName + ': usdCol=' + usdStartCol + ' hdrRow=' + headerRowIdx);

  for (let r = headerRowIdx; r < Math.min(headerRowIdx + 3, rawData.length); r++) {
    const row = rawData[r] || [];
    for (let c = 0; c < row.length; c++) {
      if (String(row[c] || '').toUpperCase().trim() === 'FROM') { colHeaderRowIdx = r; break; }
    }
    if (colHeaderRowIdx !== -1) break;
  }
  if (colHeaderRowIdx === -1) { diag.push('Sheet ' + sheetName + ': No FROM header found'); continue; }

  const colHeaderRow = rawData[colHeaderRowIdx] || [];
  let colFrom = -1, colTo = -1, colType = -1, colChildPolicy = -1;
  const colHotel = 1;

  for (let c = 0; c < colHeaderRow.length; c++) {
    const val = String(colHeaderRow[c] || '').toUpperCase().trim();
    if (val === 'FROM') colFrom = c;
    if (val === 'TO') colTo = c;
    if (val === 'TYPE' || val === 'ROOM TYPE') colType = c;
    if (val.includes('EXTRA PERSON') || val.includes('CHILD POLICY')) colChildPolicy = c;
    // Col 19 is typically the peak season surcharge column (same row as FROM/TO headers)
  }
  if (colFrom === -1 || colTo === -1 || colType === -1) {
  diag.push('Sheet ' + sheetName + ': Missing cols from=' + colFrom + ' to=' + colTo + ' type=' + colType);
  continue;
}
diag.push('Sheet ' + sheetName + ': from=' + colFrom + ' to=' + colTo + ' type=' + colType + ' usdCol=' + usdStartCol);

  const colSglUsd = usdStartCol;
  const colDblUsd = usdStartCol + 1;
  const colEbUsd = usdStartCol + 2;
  const dataStartRow = colHeaderRowIdx + 1;

  // ---- TWO-PASS: First identify hotel boundaries and collect child policies ----
  // Then generate output rows with correct child rates applied to ALL rows of a hotel

  // Pass 1: Identify hotel blocks
  const hotelBlocks = []; // { name, mealPlan, startRow, endRow, childPolicies[] }
  let currentBlock = null;

  for (let r = dataStartRow; r < rawData.length; r++) {
    const row = rawData[r]; if (!row) continue;
    const hotelVal = row[colHotel];
    if (hotelVal && String(hotelVal).trim()) {
      const hv = String(hotelVal).trim();

      // Detect meal plan change BEFORE hotel note filtering
      if (hv.toUpperCase().includes('ROOM ONLY') || hv.toUpperCase().includes('NO BREAKFAST') ||
          hv.toLowerCase().includes('not include breakfast') ||
          hv.toLowerCase().includes('room rates do not include breakfast')) {
        if (currentBlock) currentBlock.mealPlan = 5;
        // Don't treat as new hotel, continue to next row
      }
      // New hotel?
      else if (!isHotelNote(hv) && hv.length > 3) {
        if (currentBlock) {
          currentBlock.endRow = r - 1;
          hotelBlocks.push(currentBlock);
        }
        currentBlock = { name: hv, mealPlan: 1, startRow: r, endRow: rawData.length - 1, childPolicies: [], surchargeTexts: [] };
      }
    }

    // Collect child policy
    if (currentBlock && colChildPolicy >= 0 && row[colChildPolicy]) {
      const cp = String(row[colChildPolicy]).trim();
      if (cp && cp.length > 2) currentBlock.childPolicies.push(cp);
    }
    // Collect surcharge text from col 19 (peak season surcharge column)
    if (currentBlock && row[19]) {
      const st = String(row[19]).trim();
      if (st && st.length > 2) currentBlock.surchargeTexts.push(st);
    }
  }
  if (currentBlock) hotelBlocks.push(currentBlock);
  diag.push('Blocks: ' + hotelBlocks.length + ' - ' + hotelBlocks.map(b => b.name + '(' + b.startRow + '-' + b.endRow + ')').join(', '));

  // Pass 2: Generate output rows per hotel block
  for (const block of hotelBlocks) {
    if (hotelBlocks.indexOf(block) % 50 === 0) await new Promise(resolve => setTimeout(resolve, 0));

    const childRates = parseChildPolicies(block.childPolicies);

    // Parse peak season surcharge for this hotel block
    // Try all surcharge texts to find the amount
    let surchargeInfo = { amount: 0, isPercent: false };
    for (const st of block.surchargeTexts) {
      const info = parseSurchargeAmount(st);
      if (info.amount > 0) { surchargeInfo = info; break; }
    }
    // Determine contract year from date data
    let blockYear = 2026;
    for (let r = block.startRow; r <= block.endRow; r++) {
      const row = rawData[r]; if (!row) continue;
      if (row[colFrom] && isValidDate(row[colFrom])) {
        const d = new Date(row[colFrom]);
        const y = d.getFullYear();
        if (y > 2000 && y < 2100) { blockYear = y; break; }
      }
    }
    diag.push('SurchargeTexts[' + block.name.substring(0,20) + ']: ' + block.surchargeTexts.length + ' texts: ' + block.surchargeTexts.map(s => s.substring(0,40)).join(' | '));
    const peakDates = parsePeakDates(block.surchargeTexts, blockYear);
    diag.push('Block: ' + block.name + ' rows=' + block.startRow + '-' + block.endRow + ' meal=' + block.mealPlan);
    const mealId = getMealId(block.mealPlan);

    // Collect room entries with dates and prices
    const entries = [];
    let curStart = null, curEnd = null;

    let inPromotion = false;
    for (let r = block.startRow; r <= block.endRow; r++) {
      const row = rawData[r]; if (!row) continue;
      const hCell = row[colHotel] ? String(row[colHotel]).trim() : '';
      if (/^promotion\b/i.test(hCell)) { inPromotion = true; }
      if (inPromotion) continue;
      const roomTypeVal = row[colType];
      if (!roomTypeVal || !String(roomTypeVal).trim()) continue;
      const roomTypeStr = String(roomTypeVal).trim();

      if (row[colFrom] && isValidDate(row[colFrom])) curStart = formatDate(row[colFrom]);
      if (row[colTo] && isValidDate(row[colTo])) curEnd = formatDate(row[colTo]);

      const sglPrice = parseFloat(row[colSglUsd]) || 0;
      const dblPrice = parseFloat(row[colDblUsd]) || 0;
      const ebPrice = parseFloat(row[colEbUsd]) || 0;
      if (sglPrice === 0 && dblPrice === 0) continue;
      if (!curStart || !curEnd) continue;

      const roomCategory = parseRoomCategory(roomTypeStr);
      const isTriple = /triple/i.test(roomTypeStr);

      // Skip room categories that are multi-bedroom suites
      if (/\b(two|three|2|3)\s*[-\s]*bed(room)?/i.test(roomCategory)) continue;
      // Skip Suite Family, Family-first rooms, apartments, presidents, connecting, with-bathtub
      if (/^family\b/i.test(roomCategory)) continue;
      if (/^suite\s*(family|$)/i.test(roomCategory)) continue;
      if (/\b(apartment|president|connecting)\b/i.test(roomCategory)) continue;
      if (/\bwith\s+bathtub\b/i.test(roomCategory)) continue;
      entries.push({ startDate: curStart, endDate: curEnd, sglPrice, dblPrice, ebPrice, roomCategory, isTriple });
    }

    // Deduplicate entries with same category, dates, and prices
    const deduped = [];
    const seenKeys = new Set();
    for (const e of entries) {
      const key = e.roomCategory + '|' + e.startDate + '|' + e.endDate + '|' + e.sglPrice + '|' + e.dblPrice;
      if (!seenKeys.has(key)) {
        seenKeys.add(key);
        deduped.push(e);
      }
    }
    entries.length = 0;
    entries.push(...deduped);

    // Detect seasons: check if the first room category repeats later
    const firstCat = entries.length > 0 ? entries[0].roomCategory : '';
    let hasSeasons = false;
    for (let i = 1; i < entries.length; i++) {
      if (entries[i].roomCategory === firstCat) { hasSeasons = true; break; }
    }

    if (hasSeasons) {
      // Split into seasons when first category repeats
      const seasons = [];
      let curSeason = { dateRanges: [], rooms: [] };
      const seenCats = new Set();

      for (const e of entries) {
        if (seenCats.has(e.roomCategory)) {
          seasons.push(curSeason);
          curSeason = { dateRanges: [], rooms: [] };
          seenCats.clear();
        }
        seenCats.add(e.roomCategory);
        if (!curSeason.dateRanges.find(d => d.start === e.startDate && d.end === e.endDate)) {
          curSeason.dateRanges.push({ start: e.startDate, end: e.endDate });
        }
        curSeason.rooms.push(e);
      }
      if (curSeason.rooms.length > 0) seasons.push(curSeason);

      diag.push('Seasons: ' + seasons.length + ' (' + seasons.map(s => s.rooms.length + 'rooms/' + s.dateRanges.length + 'dates').join(', ') + ')');

      // Cross-multiply: each room x all date ranges in its season, with peak season splitting
      for (const season of seasons) {
        for (const room of season.rooms) {
          for (const dr of season.dateRanges) {
            // Split date range by peak season dates
            const segments = splitDateRangeByPeaks(dr.start, dr.end, peakDates);
            for (const seg of segments) {
              const surcharge = seg.isPeak ? (surchargeInfo.isPercent ? 
                0 : surchargeInfo.amount) : 0;
              const surchargePercent = seg.isPeak && surchargeInfo.isPercent ? 
                surchargeInfo.amount / 100 : 0;

              if (room.isTriple) {
                const basePrice = room.sglPrice + room.dblPrice;
                const peakPrice = surchargePercent > 0 ? basePrice * (1 + surchargePercent) : basePrice + surcharge;
                outputRows.push([seg.start, seg.end, block.mealPlan, mealId, block.name,
                  seg.isPeak ? peakPrice : basePrice, room.ebPrice, childRates.childNoBed,
                  3, room.roomCategory, 1, 'N']);
              } else {
                if (room.sglPrice > 0) {
                  const peakPrice = surchargePercent > 0 ? room.sglPrice * (1 + surchargePercent) : room.sglPrice + surcharge;
                  outputRows.push([seg.start, seg.end, block.mealPlan, mealId, block.name,
                    seg.isPeak ? peakPrice : room.sglPrice, room.ebPrice, childRates.childNoBed,
                    1, room.roomCategory, 1, 'N']);
                }
                if (room.dblPrice > 0) {
                  const peakPrice = surchargePercent > 0 ? room.dblPrice * (1 + surchargePercent) : room.dblPrice + surcharge;
                  outputRows.push([seg.start, seg.end, block.mealPlan, mealId, block.name,
                    seg.isPeak ? peakPrice : room.dblPrice, room.ebPrice, childRates.childNoBed,
                    2, room.roomCategory, 1, 'N']);
                }
                // Generate Triple from EB: when EB > 0 and room is not already Triple (skip suites)
                if (room.ebPrice > 0 && !room.isTriple) {
                  const tripleBase = room.dblPrice + room.ebPrice;
                  const triplePeak = surchargePercent > 0 ? tripleBase * (1 + surchargePercent) : tripleBase + surcharge;
                  outputRows.push([seg.start, seg.end, block.mealPlan, mealId, block.name,
                    seg.isPeak ? triplePeak : tripleBase, room.ebPrice, childRates.childNoBed,
                    3, room.roomCategory, 1, 'N']);
                }
              }
            }
          }
        }
      }
    } else {
      // No seasons: per-entry dates with peak season splitting
      for (const e of entries) {
        const segments = splitDateRangeByPeaks(e.startDate, e.endDate, peakDates);
        for (const seg of segments) {
          const surcharge = seg.isPeak ? (surchargeInfo.isPercent ? 
            0 : surchargeInfo.amount) : 0;
          const surchargePercent = seg.isPeak && surchargeInfo.isPercent ? 
            surchargeInfo.amount / 100 : 0;

          if (e.isTriple) {
            const basePrice = e.sglPrice + e.dblPrice;
            const peakPrice = surchargePercent > 0 ? basePrice * (1 + surchargePercent) : basePrice + surcharge;
            outputRows.push([seg.start, seg.end, block.mealPlan, mealId, block.name,
              seg.isPeak ? peakPrice : basePrice, e.ebPrice, childRates.childNoBed,
              3, e.roomCategory, 1, 'N']);
          } else {
            if (e.sglPrice > 0) {
              const peakPrice = surchargePercent > 0 ? e.sglPrice * (1 + surchargePercent) : e.sglPrice + surcharge;
              outputRows.push([seg.start, seg.end, block.mealPlan, mealId, block.name,
                seg.isPeak ? peakPrice : e.sglPrice, e.ebPrice, childRates.childNoBed,
                1, e.roomCategory, 1, 'N']);
            }
            if (e.dblPrice > 0) {
              const peakPrice = surchargePercent > 0 ? e.dblPrice * (1 + surchargePercent) : e.dblPrice + surcharge;
              outputRows.push([seg.start, seg.end, block.mealPlan, mealId, block.name,
                seg.isPeak ? peakPrice : e.dblPrice, e.ebPrice, childRates.childNoBed,
                2, e.roomCategory, 1, 'N']);
            }
            // Generate Triple from EB (skip suites)
            if (e.ebPrice > 0 && !e.isTriple) {
              const tripleBase = e.dblPrice + e.ebPrice;
              const triplePeak = surchargePercent > 0 ? tripleBase * (1 + surchargePercent) : tripleBase + surcharge;
              outputRows.push([seg.start, seg.end, block.mealPlan, mealId, block.name,
                seg.isPeak ? triplePeak : tripleBase, e.ebPrice, childRates.childNoBed,
                3, e.roomCategory, 1, 'N']);
            }
          }
        }
      }
    }
  }
}

diag.push('ROWS=' + outputRows.length);
if (outputRows.length === 0) {
  const diagStr = diag.slice(0, 10).join('__');
  throw new Error('NORATES_' + diagStr);
}

// ==================== OUTPUT JSON ITEMS ====================
