const roomTypeNameMap = {1:'Single', 2:'Double', 3:'Triple', 4:'Quadruple', 5:'Family'};

const outFileName = fileName.replace(/\.(xlsx|xls)$/i, '') + '_rates.xlsx';

return outputRows.map(row => ({
  json: {
    'Start Date': row[0] || '',
    'End Date': row[1] || '',
    'Meal': mealNameMap[row[2]] || 'BB',
    'Meal ID': row[2] || 1,
